 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import {
 4	  Bullseye,
 5	  Spinner,
 6	  Flex,
 7	  FlexItem,
 8	  Text,
 9	  TextContent,
10	  TextVariants,
11	} from '@patternfly/react-core';
12	import './create-storage-system.scss';
13	
14	export const ErrorHandler: React.FC<WizardStepProps> = ({
15	  children,
16	  error,
17	  loaded,
18	  loadingMessage,
19	  errorMessage,
20	}) => {
21	  const { t } = useCustomTranslation();
22	
23	  if (!loaded && !error) {
24	    return (
25	      <Bullseye className="odf-create-storage-system-wizard-body">
26	        <Flex direction={{ default: 'column' }}>
27	          <FlexItem alignSelf={{ default: 'alignSelfCenter' }}>
28	            <Spinner />
29	          </FlexItem>
30	          <FlexItem>
31	            {loadingMessage && (
32	              <TextContent>
33	                <Text>{loadingMessage}</Text>
34	              </TextContent>
35	            )}
36	          </FlexItem>
37	        </Flex>
38	      </Bullseye>
39	    );
40	  }
41	
42	  if (error) {
43	    return (
44	      <Bullseye className="odf-create-storage-system-wizard-body">
45	        <TextContent>
46	          <Text
47	            className="odf-create-storage-system-wizard-body__error"
48	            component={TextVariants.p}
49	          >
50	            {errorMessage ||
51	              t('An error has occurred: {{error}}', { error: error?.message })}
52	          </Text>
53	        </TextContent>
54	      </Bullseye>
55	    );
56	  }
57	
58	  return children;
59	};
60	
61	type WizardStepProps = {
62	  children: React.ReactElement;
63	  loaded: boolean;
64	  error: any;
65	  loadingMessage?: string;
66	  errorMessage?: React.ReactElement;
67	};

